package be.schaubroeck.lpb.rkm.rekenmotor.rsz.dmfappl;

import be.schaubroeck.lpb.rkm.rekenmotor.rsz.IsPool2Ter;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Pensioenstelsel;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.CategorieKengetalStatuutPensioenstelsel;
import lombok.AllArgsConstructor;
import org.joda.time.LocalDate;

@AllArgsConstructor
public class IsPool2TerDmfappl implements IsPool2Ter {

    private final ConstantManager constantManager;

    public boolean check(CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel, LocalDate zoekDatum) {
        Constant pool2terConstante = constantManager.getByCodeDatumSafe(Konstanten.KST_POOL2TER.getCode(), zoekDatum);
        boolean isPool2ter = pool2terConstante.getJaneen();
        return isPool2ter && isPool2ter(categorieKengetalStatuutPensioenstelsel);
    }

    private boolean isPool2ter(CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel) {
        WerkgeversCategorie werkgeversCategorie = categorieKengetalStatuutPensioenstelsel.getWerkgeversCategorie();
        Pensioenstelsel pensioenStelsel = categorieKengetalStatuutPensioenstelsel.getPensioenStelsel();
        boolean isVSpExngPct = werkgeversCategorie == WerkgeversCategorie.V_SP_EXNH_PCT;
        boolean isVastbenoemdenPensioenstelselNieuwAangsloten = werkgeversCategorie == WerkgeversCategorie.VASTBENOEMDEN_PENSIOENSTELSEL_NIEUW_AANGESLOTEN;

        boolean isEigenRegime5 = pensioenStelsel == Pensioenstelsel.EIGEN_REGIME5;
        boolean isOmobRegime10 = pensioenStelsel == Pensioenstelsel.OMOB_REGIME10;

        boolean isReplaceThis = isVastbenoemdenPensioenstelselNieuwAangsloten || isVSpExngPct;
        return (isReplaceThis && isEigenRegime5) || (isVSpExngPct && isOmobRegime10);
    }


}
